previewCss:
.darma-loader-creative-cube {
  display: inline-block;
  width: 50px;
  height: 50px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--loader-color, #6366f1), var(--loader-secondary-color, #8b5cf6));
  animation: darma-loader-creative-cube-cube 1.2s ease-in-out infinite;
  box-shadow: 0 18px 32px color-mix(in srgb, var(--loader-color, #6366f1) 22%, transparent);
}
@keyframes darma-loader-creative-cube-cube {
  0%, 100% { transform: rotate(0deg) scale(0.9); border-radius: 16px; }
  50% { transform: rotate(180deg) scale(1.08); border-radius: 50%; }
}

